/**
 * Get Scan Status By Account Group
 *
 * Get scan status for all tests in an account group with pagination, sorting, and filtering
 *
 * Retrieves scan status information by combining data from tests and test_agents tables.
 * For each test in the account group, returns the test name, status, last run information,
 * and calculated next run time from all assigned agents.
 *
 * Workflow:
 * 1. Verify user has access to the account group
 * 2. Retrieve tests associated with the account group with pagination/filter
 * 3. For each test, get test_id, test_name, and interval
 * 4. Query test_agents table using test_id to get status and last_run values
 * 5. Calculate next_run based on last_execution and test interval
 * 6. Combine results to produce scan status summary per test
 *
 * Args:
 * account_group_id: ID of the account group to get scan status for
 * page: Page number for pagination
 * per_page: Items per page for pagination
 * sort_by: Field to sort by (test_name, last_execution, overall_status, category)
 * sort_order: Sort order (asc, desc)
 * filter_text: Text to filter tests by name, category, or type
 * current_user: Current authenticated user (from JWT token)
 *
 * Returns:
 * StandardResponse containing paginated list of ScanStatusResponse with:
 * - test_id: UUID of the test
 * - test_name: Name of the test
 * - test_type: Type of test (quick, full, specific)
 * - category: Test category
 * - agents: List of agents with their status and last_run
 * - total_agents: Count of agents assigned
 * - overall_status: Aggregated status (pending, running, completed, failed)
 * - last_execution: Most recent execution timestamp
 * - next_run: Calculated next execution timestamp (last_execution + interval)
 * - is_active: Whether test is active (not deleted and assigned to at least one online agent)
 *
 * Raises:
 * 403 Forbidden: If user doesn't have access to the account group
 * 404 Not Found: If account group doesn't exist
 * 500 Internal Server Error: If database operation fails
 */
export const getScanStatusByAccountGroupApiV1ScanStatusAccountGroupIdGet = <ThrowOnError extends boolean = false>(options: Options<GetScanStatusByAccountGroupApiV1ScanStatusAccountGroupIdGetData, ThrowOnError>) => {
    return (options.client ?? client).get<GetScanStatusByAccountGroupApiV1ScanStatusAccountGroupIdGetResponses, GetScanStatusByAccountGroupApiV1ScanStatusAccountGroupIdGetErrors, ThrowOnError>({
        security: [
            {
                scheme: 'bearer',
                type: 'http'
            }
        ],
        url: '/api/v1/scan_status/{account_group_id}',
        ...options
    });
};

